import { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { toast } from 'react-hot-toast'

export const useAdminAuth = () => {
  const [isAdmin, setIsAdmin] = useState(false)
  const [isLoading, setIsLoading] = useState(true)
  const [currentUser, setCurrentUser] = useState(null)
  const navigate = useNavigate()

  useEffect(() => {
    const checkAdminStatus = () => {
      try {
        const user = localStorage.getItem('user')
        
        if (user) {
          const parsedUser = JSON.parse(user)
          setCurrentUser(parsedUser)
          
          // Check if user is admin
          const hasAdminRole = parsedUser.role === 'admin'
          const hasAdminPermissions = parsedUser.permissions?.settings === true
          
          setIsAdmin(hasAdminRole || hasAdminPermissions)
          console.log('Admin status checked:', { hasAdminRole, hasAdminPermissions, isAdmin: hasAdminRole || hasAdminPermissions })
        } else {
          setIsAdmin(false)
          setCurrentUser(null)
        }
      } catch (error) {
        console.error('Error checking admin status:', error)
        setIsAdmin(false)
        setCurrentUser(null)
      }
      
      setIsLoading(false)
    }

    checkAdminStatus()
  }, [])

  const requireAdmin = (fallbackPath = '/dashboard') => {
    if (!isLoading && !isAdmin) {
      toast.error('Access denied. Admin privileges required.')
      navigate(fallbackPath)
      return false
    }
    return true
  }

  const canAccess = (permission) => {
    if (!currentUser) return false
    
    // Admin can access everything
    if (currentUser.role === 'admin') return true
    
    // Check specific permissions
    return currentUser.permissions?.[permission] === true
  }

  return {
    isAdmin,
    isLoading,
    currentUser,
    requireAdmin,
    canAccess
  }
}
