import { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { Eye, EyeOff, Lock, User, ArrowRight } from 'lucide-react'

const Login = () => {
  const [formData, setFormData] = useState({
    username: '',
    password: ''
  })
  const [showPassword, setShowPassword] = useState(false)
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState('')
  const navigate = useNavigate()

  const handleIconClick = () => {
    setFormData({
      username: 'g@gmail.com',
      password: 'g@gmail.com'
    })
    setError('')
  }

  const resetAdminCredentials = (e) => {
    e.preventDefault()
    console.log('Resetting admin credentials...')
    const defaultAdmin = {
      id: 1,
      username: 'admin',
      email: 'admin@example.com',
      password: 'admin123',
      role: 'admin',
      fullName: 'System Administrator',
      phone: '',
      status: 'active',
      createdAt: new Date().toISOString(),
      permissions: {
        dashboard: true,
        customers: true,
        reminders: true,
        billing: true,
        settings: true
      }
    }
    localStorage.setItem('users', JSON.stringify([defaultAdmin]))
    console.log('Admin credentials reset. Use admin/admin123')
    alert('Admin credentials reset! Use admin/admin123 to login.')
  }

  const quickLoginAdmin = (e) => {
    e.preventDefault()
    setFormData({
      username: 'admin',
      password: 'admin123'
    })
    setError('')
  }

  const quickLoginGmail = (e) => {
    e.preventDefault()
    setFormData({
      username: 'g@gmail.com',
      password: 'g@gmail.com'
    })
    setError('')
  }

  const debugUsers = (e) => {
    e.preventDefault() // Prevent form submission
    const storedUsers = localStorage.getItem('users')
    console.log('=== DEBUG USERS IN LOCALSTORAGE ===')
    if (storedUsers) {
      const users = JSON.parse(storedUsers)
      console.log('Total users:', users.length)
      users.forEach((user, index) => {
        console.log(`User ${index + 1}:`, {
          id: user.id,
          username: user.username,
          email: user.email,
          fullName: user.fullName,
          role: user.role,
          hasPassword: !!user.password,
          passwordLength: user.password ? user.password.length : 0,
          status: user.status
        })
      })
      
      // Check for kalpana specifically
      const kalpanaUser = users.find(u => 
        u.username?.toLowerCase() === 'kalpana' || 
        u.email?.toLowerCase() === 'kalpana' ||
        u.fullName?.toLowerCase() === 'kalpana'
      )
      console.log('Kalpana user found:', kalpanaUser)
      
      // Show alert with kalpana info
      if (kalpanaUser) {
        const message = kalpanaUser.password 
          ? `Kalpana found: Username=${kalpanaUser.username || kalpanaUser.email}, Has Password=YES (${kalpanaUser.password.length} chars)`
          : `Kalpana found: Username=${kalpanaUser.username || kalpanaUser.email}, Has Password=NO - This is the problem!`
        alert(message)
        console.log('Kalpana user details:', kalpanaUser)
      } else {
        alert('Kalpana user not found in localStorage')
        console.log('Kalpana user not found')
      }
    } else {
      alert('No users found in localStorage')
      console.log('No users found in localStorage')
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    setIsLoading(true)
    setError('')

    try {
      console.log('=== LOGIN DEBUG ===')
      console.log('Form data:', formData)
      
      // Check against stored users in localStorage
      const storedUsers = localStorage.getItem('users')
      let users = []
      
      console.log('Stored users raw:', storedUsers)
      
      if (storedUsers) {
        users = JSON.parse(storedUsers)
        console.log('Parsed users:', users)
      } else {
        console.log('No users found, creating default admin')
        // Create default admin user if no users exist
        users = [{
          id: 1,
          username: 'admin',
          email: 'admin@example.com',
          password: 'admin123',
          role: 'admin',
          fullName: 'System Administrator',
          phone: '',
          status: 'active',
          createdAt: new Date().toISOString(),
          permissions: {
            dashboard: true,
            customers: true,
            reminders: true,
            billing: true,
            settings: true
          }
        }]
        localStorage.setItem('users', JSON.stringify(users))
        console.log('Default admin created and saved')
      }

      // Validate credentials against stored users
      const foundUser = users.find(user => {
        const usernameMatch = user.username === formData.username
        const emailMatch = user.email === formData.username
        const passwordMatch = user.password === formData.password
        console.log(`Checking user: ${user.username}, hasPassword: ${!!user.password}, usernameMatch: ${usernameMatch}, emailMatch: ${emailMatch}, passwordMatch: ${passwordMatch}`)
        console.log(`User data:`, { username: user.username, email: user.email, hasPassword: !!user.password, role: user.role })
        return (usernameMatch || emailMatch) && passwordMatch
      })

      console.log('Found user:', foundUser)

      // Also allow the hardcoded admin credentials for fallback
      const isHardcodedAdmin = formData.username === 'g@gmail.com' && formData.password === 'g@gmail.com'
      console.log('Is hardcoded admin:', isHardcodedAdmin)

      if (foundUser || isHardcodedAdmin) {
        console.log('Login successful!')
        // Successful login - create user session
        const userSession = foundUser || {
          id: 1,
          name: 'Admin User',
          username: formData.username,
          email: formData.username,
          role: 'admin',
          avatar: 'A',
          permissions: {
            dashboard: true,
            customers: true,
            reminders: true,
            billing: true,
            settings: true
          }
        }
        
        localStorage.setItem('authToken', 'mock-jwt-token')
        localStorage.setItem('user', JSON.stringify(userSession))
        
        console.log('User session saved:', userSession)
        navigate('/')
      } else {
        console.log('Login failed - no matching user found')
        // Failed login - show error
        setError('Invalid credentials. Try admin/admin123 or g@gmail.com/g@gmail.com')
      }
      
    } catch (err) {
      console.error('Login error:', err)
      setError('Login failed. Please try again.')
    } finally {
      setIsLoading(false)
    }
  }

  const handleInputChange = (e) => {
    const { name, value } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: value
    }))
    if (error) setError('')
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-indigo-900 via-blue-900 to-purple-900 flex items-center justify-center p-4">
      {/* Animated Background Elements */}
      <div className="absolute inset-0 overflow-hidden">
        <div className="absolute -top-40 -right-40 w-96 h-96 bg-gradient-to-br from-indigo-500/20 to-blue-500/20 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute -bottom-40 -left-40 w-96 h-96 bg-gradient-to-br from-purple-500/20 to-violet-500/20 rounded-full blur-3xl animate-pulse delay-1000"></div>
        <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-[600px] h-[600px] bg-gradient-to-br from-blue-500/10 to-indigo-500/10 rounded-full blur-3xl animate-pulse delay-500"></div>
        
        {/* Floating Particles */}
        <div className="absolute top-20 left-20 w-2 h-2 bg-white/30 rounded-full animate-ping"></div>
        <div className="absolute top-40 right-32 w-3 h-3 bg-indigo-400/30 rounded-full animate-ping delay-300"></div>
        <div className="absolute bottom-32 left-40 w-2 h-2 bg-blue-400/30 rounded-full animate-ping delay-700"></div>
        <div className="absolute bottom-20 right-20 w-4 h-4 bg-purple-400/30 rounded-full animate-ping delay-1000"></div>
      </div>

      {/* Login Container */}
      <div className="relative z-10 w-full max-w-md mx-auto">
        <div className="bg-white/10 backdrop-blur-2xl rounded-3xl shadow-2xl overflow-hidden border border-white/20 p-8">
          {/* Logo */}
          <div className="text-center mb-8">
            <h1 className="text-3xl font-bold text-white mb-2">Welcome Back</h1>
            <p className="text-white/70 text-sm">Enter your credentials to access the system</p>
            <div 
              onClick={handleIconClick}
              className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-br from-indigo-500 to-purple-500 rounded-2xl shadow-lg mt-4 transform hover:scale-110 transition-all duration-300 cursor-pointer active:scale-95"
            >
              <Lock className="h-8 w-8 text-white" />
            </div>
            <p className="text-white/50 text-xs mt-2">Click icon to fill credentials</p>
          </div>

          {/* Error Message */}
          {error && (
            <div className="mb-6 p-4 bg-red-500/20 border border-red-500/30 rounded-lg backdrop-blur">
              <p className="text-sm text-red-200">{error}</p>
            </div>
          )}

          {/* Login Form */}
          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label htmlFor="username" className="block text-sm font-medium text-white/90 mb-2">
                Username
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <User className="h-5 w-5 text-white/50" />
                </div>
                <input
                  id="username"
                  name="username"
                  type="text"
                  value={formData.username}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-4 bg-white/10 backdrop-blur border border-white/20 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all duration-300 text-white placeholder-white/50 hover:bg-white/15"
                  placeholder="Enter your username"
                  required
                />
              </div>
            </div>

            <div>
              <label htmlFor="password" className="block text-sm font-medium text-white/90 mb-2">
                Password
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <Lock className="h-5 w-5 text-white/50" />
                </div>
                <input
                  id="password"
                  name="password"
                  type={showPassword ? 'text' : 'password'}
                  value={formData.password}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-14 py-4 bg-white/10 backdrop-blur border border-white/20 rounded-xl focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all duration-300 text-white placeholder-white/50 hover:bg-white/15"
                  placeholder="Enter your password"
                  required
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute inset-y-0 right-0 pr-4 flex items-center"
                >
                  {showPassword ? (
                    <EyeOff className="h-5 w-5 text-white/50 hover:text-white/70 transition-colors" />
                  ) : (
                    <Eye className="h-5 w-5 text-white/50 hover:text-white/70 transition-colors" />
                  )}
                </button>
              </div>
            </div>

            <div className="flex items-center justify-between">
              <div className="flex items-center">
                <input
                  id="remember"
                  type="checkbox"
                  className="h-4 w-4 text-indigo-600 focus:ring-indigo-500 border-white/30 rounded bg-white/10"
                />
                <label htmlFor="remember" className="ml-2 block text-sm text-white/80">
                  Remember me
                </label>
              </div>
              <a href="#" className="text-sm text-indigo-300 hover:text-indigo-200 transition-colors">
                Forgot password?
              </a>
            </div>

            <button
              type="submit"
              disabled={isLoading}
              className="w-full bg-gradient-to-r from-indigo-500 to-purple-500 text-white py-4 px-6 rounded-xl font-semibold hover:from-indigo-600 hover:to-purple-600 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:ring-offset-2 focus:ring-offset-transparent transition-all duration-300 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg hover:shadow-indigo-500/25 transform hover:-translate-y-0.5 flex items-center justify-center gap-3"
            >
              {isLoading ? (
                <>
                  <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  Signing in...
                </>
              ) : (
                <>
                  Sign In
                  <ArrowRight className="h-5 w-5" />
                </>
              )}
            </button>

            {/* Quick Login Buttons */}
            <div className="mt-6 space-y-2">
              <div className="text-center text-white/60 text-xs mb-2">Quick Login:</div>
              <div className="grid grid-cols-4 gap-2">
                <button
                  type="button"
                  onClick={quickLoginAdmin}
                  className="bg-green-600/20 border border-green-500/30 text-green-300 py-2 px-3 rounded-lg text-xs hover:bg-green-600/30 transition-colors"
                >
                  Admin
                </button>
                <button
                  type="button"
                  onClick={quickLoginGmail}
                  className="bg-blue-600/20 border border-blue-500/30 text-blue-300 py-2 px-3 rounded-lg text-xs hover:bg-blue-600/30 transition-colors"
                >
                  Gmail
                </button>
                <button
                  type="button"
                  onClick={resetAdminCredentials}
                  className="bg-red-600/20 border border-red-500/30 text-red-300 py-2 px-3 rounded-lg text-xs hover:bg-red-600/30 transition-colors"
                >
                  Reset
                </button>
                <button
                  type="button"
                  onClick={debugUsers}
                  className="bg-purple-600/20 border border-purple-500/30 text-purple-300 py-2 px-3 rounded-lg text-xs hover:bg-purple-600/30 transition-colors"
                >
                  Debug
                </button>
              </div>
            </div>
          </form>
        </div>

        {/* Footer */}
        <div className="text-center mt-8 text-white/60 text-sm">
          <p>&copy; 2026 Vetri. All rights reserved.</p>
        </div>
      </div>
    </div>
  )
}

export default Login
