import { useState, useEffect } from 'react'
import { Plus, Edit2, Trash2, Save, X, Search, Filter } from 'lucide-react'
import { toast } from 'react-hot-toast'

// Helper function to get API base URL
const getApiUrl = (endpoint) => {
  const baseUrl = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
    ? 'http://localhost:5001'
    : 'https://two026backend.onrender.com'
  return `${baseUrl}${endpoint}`
}

const SubServices = () => {
  const [subServices, setSubServices] = useState([])
  const [services, setServices] = useState([])
  const [showAddForm, setShowAddForm] = useState(false)
  const [editingSubService, setEditingSubService] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedService, setSelectedService] = useState('')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [formData, setFormData] = useState({
    subServiceName: '',
    serviceId: '',
    price: '',
    unit: '',
    extras: '',
    description: '',
    isActive: true
  })

  // Fetch services for dropdown
  const fetchServices = async () => {
    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch(getApiUrl('/api/services'), {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (response.ok) {
        const data = await response.json()
        setServices(Array.isArray(data) ? data : [])
      } else {
        console.error('Failed to fetch services')
      }
    } catch (err) {
      console.error('Error fetching services:', err)
    }
  }

  // Fetch sub-services from backend
  const fetchSubServices = async () => {
    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch(getApiUrl('/api/subservices'), {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (response.ok) {
        const data = await response.json()
        console.log('SubServices API Response:', data)
        setSubServices(Array.isArray(data) ? data : [])
      } else {
        setError('Failed to fetch sub-services')
      }
    } catch (err) {
      console.error('Error fetching sub-services:', err)
      setError('Failed to fetch sub-services')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchServices()
    fetchSubServices()
  }, [])

  // Save sub-service
  const saveSubService = async () => {
    try {
      const token = localStorage.getItem('authToken')
      const url = editingSubService ? getApiUrl(`/api/subservices/${editingSubService._id}`) : getApiUrl('/api/subservices')
      const method = editingSubService ? 'PUT' : 'POST'

      const subServiceData = {
        subServiceName: formData.subServiceName,
        serviceId: formData.serviceId,
        price: parseFloat(formData.price),
        unit: formData.unit,
        extras: formData.extras,
        description: formData.description,
        isActive: formData.isActive
      }

      console.log('Saving sub-service:', subServiceData)
      console.log('URL:', url)
      console.log('Method:', method)

      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(subServiceData)
      })

      if (response.ok) {
        toast.success(editingSubService ? 'Sub-service updated successfully!' : 'Sub-service added successfully!')
        setShowAddForm(false)
        setEditingSubService(null)
        fetchSubServices() // Refresh sub-services list
      } else {
        const errorData = await response.json()
        console.error('Save failed:', errorData)
        toast.error(`Failed to save sub-service: ${errorData.message || 'Unknown error'}`)
      }
    } catch (error) {
      console.error('Error saving sub-service:', error)
      toast.error('Error saving sub-service')
    }
  }

  const handleSubmit = (e) => {
    e.preventDefault()
    saveSubService()
  }

  // Delete sub-service
  const deleteSubService = async (id) => {
    if (!confirm('Are you sure you want to delete this sub-service?')) {
      return
    }

    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch(getApiUrl(`/api/subservices/${id}`), {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })

      if (response.ok) {
        toast.success('Sub-service deleted successfully!')
        // Clear localStorage cache to force refresh in other components
        localStorage.removeItem('services')
        localStorage.removeItem('subServices')
        fetchSubServices() // Refresh sub-services list
      } else {
        toast.error('Failed to delete sub-service')
      }
    } catch (err) {
      console.error('Error deleting sub-service:', err)
      toast.error('Failed to delete sub-service')
    }
  }

  // Filter sub-services
  const filteredSubServices = subServices.filter(subService =>
    subService.subServiceName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
    (selectedService && subService.serviceId === selectedService)
  )

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }))
  }

  const handleEdit = (subService) => {
    setEditingSubService(subService)
    setShowAddForm(true)
    
    // Handle both populated and non-populated serviceId
    const serviceId = subService.serviceId?._id || subService.serviceId || ''
    
    // Set form data with existing sub-service data
    setFormData({
      subServiceName: subService.subServiceName || '',
      serviceId: serviceId,
      price: subService.price || '',
      unit: subService.unit || '',
      extras: subService.extras || '',
      description: subService.description || '',
      isActive: subService.isActive !== undefined ? subService.isActive : true
    })
    
    if (serviceId) {
      setSelectedService(serviceId)
    }
    
    console.log('Editing sub-service:', subService)
    console.log('Service ID extracted:', serviceId)
  }

  const handleAdd = () => {
    setEditingSubService(null)
    setShowAddForm(true)
    setFormData({
      subServiceName: '',
      serviceId: '',
      price: '',
      unit: '',
      extras: '',
      description: '',
      isActive: true
    })
    setSelectedService('')
  }

  const handleClose = () => {
    setShowAddForm(false)
    setEditingSubService(null)
    setFormData({
      subServiceName: '',
      serviceId: '',
      price: '',
      unit: '',
      extras: '',
      description: '',
      isActive: true
    })
    setSelectedService('')
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Sub-service Management</h2>
        <button
          onClick={handleAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition-colors text-base font-medium"
        >
          <Plus size={20} />
          Add Sub-service
        </button>
      </div>

      {/* Filters */}
      <div className="mb-6 grid grid-cols-1 md:grid-cols-2 gap-4">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
          <input
            type="text"
            placeholder="Search sub-services..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 w-full"
          />
        </div>
        <div>
          <select
            value={selectedService}
            onChange={(e) => setSelectedService(e.target.value)}
            className="w-full px-3 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500"
          >
            <option value="">Filter by Service</option>
            {services.map(service => (
              <option key={service._id} value={service._id}>
                {service.serviceName}
              </option>
            ))}
          </select>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="mb-4 p-4 bg-red-100 border border-red-400 text-red-700 rounded-lg">
          {error}
        </div>
      )}

      {/* Sub-services List */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Sub-service Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Service</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Price</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Unit</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredSubServices.length === 0 ? (
                <tr>
                  <td colSpan="6" className="px-6 py-4 text-center text-gray-500">
                    No sub-services found
                  </td>
                </tr>
              ) : (
                filteredSubServices.map((subService) => (
                  <tr key={subService._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900">{subService.subServiceName}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {subService.serviceId?.serviceName || 
                       services.find(s => s._id === subService.serviceId)?.serviceName || 
                       'Unknown'}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      ₹{subService.price}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {subService.unit}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                        subService.isActive ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                      }`}>
                        {subService.isActive ? 'Active' : 'Inactive'}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={() => handleEdit(subService)}
                        className="text-blue-600 hover:text-blue-900 mr-3 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Edit Sub-service"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button
                        onClick={() => deleteSubService(subService._id)}
                        className="text-red-600 hover:text-red-900 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        title="Delete Sub-service"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Sub-service Modal */}
      {showAddForm && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-medium text-gray-900">
                {editingSubService ? 'Edit Sub-service' : 'Add New Sub-service'}
              </h3>
              <button
                onClick={handleClose}
                className="text-gray-400 hover:text-gray-500"
              >
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Service</label>
                <select
                  name="serviceId"
                  value={formData.serviceId}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="">Select Service</option>
                  {services.map(service => (
                    <option key={service._id} value={service._id}>
                      {service.serviceName}
                    </option>
                  ))}
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Sub-service Name</label>
                <input
                  type="text"
                  name="subServiceName"
                  value={formData.subServiceName}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Price</label>
                <input
                  type="number"
                  name="price"
                  step="0.01"
                  min="0"
                  value={formData.price}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Unit</label>
                <select
                  name="unit"
                  value={formData.unit}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="">Select Unit</option>
                  <option value="Nos">Nos</option>
                  <option value="Pack">Pack</option>
                  <option value="Kg">Kg</option>
                  <option value="Liter">Liter</option>
                  <option value="Meter">Meter</option>
                  <option value="Box">Box</option>
                  <option value="Piece">Piece</option>
                </select>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Extras</label>
                <input
                  type="text"
                  name="extras"
                  value={formData.extras}
                  onChange={handleInputChange}
                  placeholder="Additional charges or notes"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  rows="3"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                <select
                  name="isActive"
                  value={formData.isActive.toString()}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="true">Active</option>
                  <option value="false">Inactive</option>
                </select>
              </div>

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={handleClose}
                  className="px-6 py-3 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 text-base font-medium transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-3 bg-blue-600 text-white rounded-md hover:bg-blue-700 flex items-center gap-2 text-base font-medium transition-colors"
                >
                  <Save size={18} />
                  {editingSubService ? 'Update' : 'Save'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default SubServices
