import { useState, useEffect } from 'react'
import { Plus, Search, Edit2, Trash2, Package, AlertCircle, TrendingUp, TrendingDown, Box, Layers, X } from 'lucide-react'
import toast from 'react-hot-toast'
import { stockAPI } from '../../services/api'

const StockManagement = () => {
  // Load stock items from API on component mount
  const [stockItems, setStockItems] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState(null)

  // Fetch stock data from API
  useEffect(() => {
    const fetchStockData = async () => {
      try {
        const response = await stockAPI.getAll()
        setStockItems(response.data || [])
        setLoading(false)
        setError(null)
      } catch (error) {
        console.error('Error fetching stock data:', error)
        setError('Failed to fetch stock data')
        setLoading(false)
        
        // Fallback to localStorage if API fails
        const savedStock = localStorage.getItem('stockManagement')
        if (savedStock) {
          try {
            setStockItems(JSON.parse(savedStock))
          } catch (parseError) {
            console.error('Error parsing saved stock:', parseError)
          }
        }
      }
    }
    
    fetchStockData()
  }, [])

  // Save stock items to localStorage whenever they change (backup only)
  useEffect(() => {
    localStorage.setItem('stockManagement', JSON.stringify(stockItems))
  }, [stockItems])

  // State for form fields
  const [formData, setFormData] = useState({
    category: '',
    subCategory: '',
    itemName: '', // Added missing required field
    currentStock: 0,
    minStock: 0,
    restock: 0,
    unit: '',
    unitPrice: 0,
    supplier: '',
    lastRestocked: '',
    notes: ''
  })

  // State declarations
  const [searchTerm, setSearchTerm] = useState('')
  const [showAddForm, setShowAddForm] = useState(false)
  const [editingItem, setEditingItem] = useState(null)
  const [selectedCategory, setSelectedCategory] = useState('')
  const [selectedSubCategory, setSelectedSubCategory] = useState('')

  // Update form when editingItem changes - removed DOM manipulation since using controlled components

  const categories = ['Paper', 'Ink', 'Lamination', 'Binding', 'Printing Plates', 'Chemicals', 'Tools', 'Packaging']
  const subCategories = {
    'Paper': ['A4', 'A3', 'A5', 'Letter', 'Legal', 'Tabloid', 'Photo Paper', 'Cardstock', 'Transparency', 'Label Paper', 'Newsprint', 'Art Paper', 'Recycled Paper'],
    'Ink': ['Black', 'Color', 'Cyan', 'Magenta', 'Yellow', 'Photo Black', 'Matte Black', 'Gray Ink', 'White Ink', 'Metallic Ink', 'UV Ink', 'Solvent Ink', 'Eco-Solvent Ink'],
    'Lamination': ['Matte', 'Glossy', 'Satin', 'Velvet', 'Textured', 'Anti-Scratch', 'UV Protection', 'Waterproof', 'Heat Resistant', 'Cold Lamination', 'Self-Adhesive'],
    'Binding': ['Spiral', 'Comb', 'Wire', 'Perfect Bound', 'Saddle Stitch', 'Case Bound', 'Thermal', 'Coil', 'Plastic Coil', 'Double Loop', 'Twin Loop'],
    'Printing Plates': ['Aluminum Plates', 'Polymer Plates', 'Flexographic Plates', 'CTP Plates', 'Digital Plates', 'Screen Printing Plates', 'Offset Plates'],
    'Chemicals': ['Developer', 'Fixer', 'Cleaning Solution', 'Fountain Solution', 'Plate Cleaner', 'Blanket Wash', 'Injet Cleaner', 'Toner', 'Drum Cleaner'],
    'Tools': ['Paper Cutter', 'Guillotine', 'Binding Machine', 'Laminator', 'Folding Machine', 'Scoring Machine', 'Perforator', 'Creaser', 'Corner Rounder'],
    'Packaging': ['Cardboard Boxes', 'Bubble Wrap', 'Shrink Wrap', 'Foam Inserts', 'Paper Bags', 'Plastic Bags', 'Envelopes', 'Mailers', 'Tape', 'Labels']
  }

  const filteredItems = stockItems.filter(item => {
    const matchesSearch = 
      (item.category && item.category.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (item.subCategory && item.subCategory.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (item.supplier && item.supplier.toLowerCase().includes(searchTerm.toLowerCase())) ||
      (item.notes && item.notes.toLowerCase().includes(searchTerm.toLowerCase()))
    
    const matchesCategory = !selectedCategory || item.category === selectedCategory
    const matchesSubCategory = !selectedSubCategory || item.subCategory === selectedSubCategory
    
    return matchesSearch && matchesCategory && matchesSubCategory
  })

  const getStockStatus = (current, min) => {
    if (current <= min * 0.5) return { status: 'critical', color: 'red', text: 'Critical' }
    if (current <= min) return { status: 'low', color: 'amber', text: 'Low Stock' }
    if (current >= min * 3) return { status: 'high', color: 'blue', text: 'High Stock' }
    return { status: 'normal', color: 'green', text: 'Normal' }
  }

  const getStockBadgeClasses = (status) => {
    const baseClasses = 'px-2 py-1 rounded-full text-xs font-medium'
    switch (status.color) {
      case 'red': return `${baseClasses} bg-red-100 text-red-700 blink-red glow-red`
      case 'amber': return `${baseClasses} bg-amber-100 text-amber-700 blink-amber glow-amber`
      case 'blue': return `${baseClasses} bg-blue-100 text-blue-700`
      case 'green': return `${baseClasses} bg-green-100 text-green-700`
      default: return `${baseClasses} bg-gray-100 text-gray-700`
    }
  }

  const handleDelete = async (id) => {
    if (window.confirm('Are you sure you want to delete this stock item?')) {
      try {
        await stockAPI.delete(id)
        setStockItems(stockItems.filter(item => item._id !== id && item.id !== id))
        console.log('Stock item deleted successfully')
        toast.success('Stock item deleted successfully!')
      } catch (error) {
        console.error('Error deleting stock item:', error)
        toast.error('Failed to delete stock item. Please try again.')
      }
    }
  }

  const handleEdit = (item) => {
    setEditingItem(item)
    setFormData({
      itemName: item.itemName || '', // Added missing required field
      category: item.category || '',
      subCategory: item.subCategory || '',
      currentStock: item.currentStock || 0,
      minStock: item.minStock || 0,
      restock: 0, // Reset restock to 0 when editing
      unit: item.unit || '',
      unitPrice: item.unitPrice || 0,
      supplier: item.supplier || '',
      lastRestocked: item.lastRestocked || '',
      notes: item.notes || ''
    })
    setShowAddForm(true)
  }

  const handleSave = async (formData) => {
    try {
      // Calculate total stock (current stock + restock)
      const totalStock = (formData.currentStock || 0) + (formData.restock || 0)
      
      const itemData = {
        ...formData,
        currentStock: totalStock // Save the total stock
      }

      if (editingItem) {
        // Update existing item via API
        await stockAPI.update({
          ...itemData,
          _id: editingItem._id || editingItem.id
        })
        setStockItems(stockItems.map(item => (item._id === editingItem._id || item.id === editingItem.id) ? { ...itemData, _id: editingItem._id || editingItem.id, id: editingItem._id || editingItem.id } : item))
        console.log('Stock item updated successfully:', itemData)
      } else {
        // Create new item via API
        const response = await stockAPI.create(itemData)
        setStockItems([...stockItems, { ...response.data, id: response.data._id || Date.now() }])
        console.log('Stock item created successfully:', response.data)
      }

      // Close form and reset state
      setShowAddForm(false)
      setEditingItem(null)
      setFormData({
        category: '',
        subCategory: '',
        currentStock: 0,
        minStock: 0,
        restock: 0,
        unit: '',
        unitPrice: 0,
        supplier: '',
        lastRestocked: '',
        notes: ''
      })
      
      toast.success(editingItem ? 'Stock item updated successfully!' : 'Stock item added successfully!')
    } catch (error) {
      console.error('Error saving stock item:', error)
      toast.error('Failed to save stock item. Please try again.')
    }
  }

  // Auto-load existing stock when category/subcategory changes
  const handleCategoryChange = (category) => {
    // Check if this category already has items and auto-load first available
    const existingItems = stockItems.filter(item => item.category === category)
    if (existingItems.length > 0 && !editingItem) {
      // Load the first existing item's data as reference
      const firstItem = existingItems[0]
      setFormData(prev => ({ 
        ...prev, 
        category,
        subCategory: '',
        currentStock: firstItem.currentStock || 0,
        restock: 0
      }))
      
      console.log(`Auto-loaded stock for category ${category}:`, firstItem.currentStock)
    } else if (!editingItem) {
      // Reset to 0 if no existing items
      setFormData(prev => ({ 
        ...prev, 
        category,
        subCategory: '',
        currentStock: 0,
        restock: 0
      }))
    }
  }

  const handleSubCategoryChange = (category, subCategory) => {
    // Check if this exact category/subcategory combination exists
    const existingItem = stockItems.find(item => 
      item.category === category && item.subCategory === subCategory
    )
    
    if (existingItem && !editingItem) {
      // Auto-load the existing stock
      setFormData(prev => ({ 
        ...prev, 
        subCategory,
        currentStock: existingItem.currentStock || 0,
        restock: 0
      }))
      
      console.log(`Auto-loaded stock for ${category} - ${subCategory}:`, existingItem.currentStock)
    } else if (!editingItem) {
      // Set to 0 if no existing combination
      setFormData(prev => ({ 
        ...prev, 
        subCategory,
        currentStock: 0,
        restock: 0
      }))
    }
  }

  const getTotalValue = () => {
    return stockItems.reduce((sum, item) => sum + (item.currentStock * item.unitPrice), 0)
  }

  const getLowStockItems = () => {
    return stockItems.filter(item => item.currentStock <= item.minStock).length
  }

  const getCriticalItems = () => {
    return stockItems.filter(item => item.currentStock <= item.minStock * 0.5).length
  }

  // Get total stock by sub-category
  const getTotalStockBySubCategory = (subCategory) => {
    return stockItems
      .filter(item => item.subCategory === subCategory)
      .reduce((total, item) => total + item.currentStock, 0)
  }

  // Get unique sub-categories with their totals
  const getSubCategoryTotals = () => {
    const totals = {}
    stockItems.forEach(item => {
      if (!totals[item.subCategory]) {
        totals[item.subCategory] = 0
      }
      totals[item.subCategory] += item.currentStock
    })
    return totals
  }

  // Calculate days since restock
  const getDaysSinceRestock = (lastRestocked) => {
    if (!lastRestocked) return 0
    
    const restockDate = new Date(lastRestocked)
    const today = new Date()
    const diffTime = Math.abs(today - restockDate)
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24))
    
    return diffDays
  }

  // Handle category filter change
  const handleCategoryFilterChange = (category) => {
    setSelectedCategory(category)
    setSelectedSubCategory('') // Reset sub-category when category changes
  }

  // Handle sub-category filter change
  const handleSubCategoryFilterChange = (subCategory) => {
    setSelectedSubCategory(subCategory)
  }

  // Clear all filters
  const clearFilters = () => {
    setSelectedCategory('')
    setSelectedSubCategory('')
    setSearchTerm('')
  }

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">Stock Management</h2>
          <p className="text-gray-600 mt-1">Manage printing supplies inventory (Papers, Ink, Lamination)</p>
        </div>
        <button
          onClick={() => {
            setShowAddForm(true)
            setEditingItem(null)
            setFormData({
              category: '',
              subCategory: '',
              currentStock: 0,
              minStock: 0,
              restock: 0,
              unit: '',
              unitPrice: 0,
              supplier: '',
              lastRestocked: '',
              notes: ''
            })
          }}
          className="btn-primary flex items-center space-x-2"
        >
          <Plus className="h-4 w-4" />
          <span>Add Stock Item</span>
        </button>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-gradient-to-br from-blue-50 to-blue-100 rounded-xl p-4 border border-blue-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-blue-600 font-medium">Total Items</p>
              <p className="text-2xl font-bold text-gray-900">{stockItems.length}</p>
            </div>
            <Package className="h-8 w-8 text-blue-500" />
          </div>
        </div>

        <div className="bg-gradient-to-br from-amber-50 to-amber-100 rounded-xl p-4 border border-amber-200">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-sm text-amber-600 font-medium">Low Stock</p>
              <p className="text-2xl font-bold text-gray-900">{getLowStockItems()}</p>
            </div>
            <AlertCircle className="h-8 w-8 text-amber-500" />
          </div>
        </div>
      </div>

      {/* Search and Filter */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-4">
        <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
          {/* Search */}
          <div className="relative">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400 h-5 w-5" />
            <input
              type="text"
              placeholder="Search by supplier or notes..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="input-field pl-10"
            />
          </div>

          {/* Category Filter */}
          <div>
            <select
              value={selectedCategory}
              onChange={(e) => handleCategoryFilterChange(e.target.value)}
              className="input-field"
            >
              <option value="">All Categories</option>
              {categories.map(category => (
                <option key={category} value={category}>{category}</option>
              ))}
            </select>
          </div>

          {/* Sub Category Filter */}
          <div>
            <select
              value={selectedSubCategory}
              onChange={(e) => handleSubCategoryFilterChange(e.target.value)}
              disabled={!selectedCategory}
              className="input-field disabled:bg-gray-100"
            >
              <option value="">All Sub Categories</option>
              {selectedCategory && subCategories[selectedCategory]?.map(subCategory => (
                <option key={subCategory} value={subCategory}>{subCategory}</option>
              ))}
            </select>
          </div>

          {/* Clear Filters */}
          <div>
            <button
              onClick={clearFilters}
              className="w-full px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200 transition-colors flex items-center justify-center gap-2"
            >
              <X size={16} />
              Clear Filters
            </button>
          </div>
        </div>
      </div>

      {/* Stock Items Table */}
      <div className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50 border-b border-gray-200">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Item Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Category</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Sub Category</th>
                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Current Stock</th>
                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Total Stock</th>
                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Min Stock</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Unit</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Unit Price</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Supplier</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Last Restocked</th>
                <th className="px-6 py-3 text-center text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredItems.map((item) => {
                const stockStatus = getStockStatus(item.currentStock, item.minStock)
                const totalValue = item.currentStock * item.unitPrice
                
                return (
                  <tr key={item._id || item.id} className="hover:bg-gray-50 transition-colors">
                    <td className="px-6 py-4">
                      <div>
                        <div className="text-sm font-medium text-gray-900">{item.itemName}</div>
                        <div className="text-xs text-gray-500">{item.notes}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <div>
                        <div className="text-sm font-medium text-gray-900">{item.category}</div>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-sm text-gray-900">{item.subCategory}</span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className="text-sm font-medium text-gray-900">{item.currentStock}</span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex flex-col items-center">
                        <span className="text-sm font-semibold text-blue-600">
                          {getTotalStockBySubCategory(item.subCategory)}
                        </span>
                        <span className="text-xs text-gray-500">{item.unit}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className="text-sm text-gray-500">{item.minStock}</span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-sm text-gray-900">{item.unit}</span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <span className="text-sm text-gray-900">₹{item.unitPrice.toFixed(2)}</span>
                    </td>
                    <td className="px-6 py-4">
                      <span className="text-sm text-gray-900">{item.supplier}</span>
                    </td>
                    <td className="px-6 py-4">
                      <div className="flex flex-col">
                        <span className="text-sm text-gray-900">
                          {item.lastRestocked ? new Date(item.lastRestocked).toLocaleDateString('en-US', {
                            year: 'numeric',
                            month: 'short',
                            day: 'numeric'
                          }) : 'Not set'}
                        </span>
                        {item.lastRestocked && (
                          <span className="text-xs text-gray-500">
                            {getDaysSinceRestock(item.lastRestocked)} days ago
                          </span>
                        )}
                      </div>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <span className={getStockBadgeClasses(stockStatus)}>
                        {stockStatus.text}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end space-x-2">
                        <button
                          onClick={() => handleEdit(item)}
                          className="text-blue-600 hover:text-blue-800 transition-colors"
                          title="Edit"
                        >
                          <Edit2 className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => handleDelete(item._id || item.id)}
                          className="text-red-600 hover:text-red-800 transition-colors"
                          title="Delete"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                )
              })}
              {filteredItems.length === 0 && (
                <tr>
                  <td colSpan="12" className="px-6 py-8 text-center text-gray-500">
                    No stock items found. Click "Add Stock Item" to add items to your inventory.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Stock Item Modal */}
      {showAddForm && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg w-full max-w-2xl max-h-[90vh] overflow-hidden">
            {/* Modal Header */}
            <div className="bg-gradient-to-r from-blue-600 to-blue-700 text-white p-6">
              <div className="flex items-center justify-between">
                <h3 className="text-lg font-semibold">
                  {editingItem ? 'Edit Stock Item' : 'Add New Stock Item'}
                </h3>
                <button
                  onClick={() => setShowAddForm(false)}
                  className="text-white hover:text-gray-200 transition-colors"
                >
                  <X size={24} />
                </button>
              </div>
            </div>

            {/* Modal Body */}
            <div className="p-6">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                  <select 
                    className="input-field" 
                    value={formData.category}
                    onChange={(e) => {
                      const category = e.target.value
                      setFormData(prev => ({ ...prev, category, subCategory: '' }))
                      handleCategoryChange(category)
                    }}
                  >
                    <option value="">Select Category</option>
                    {categories.map(category => (
                      <option key={category} value={category}>{category}</option>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Sub Category</label>
                  <select 
                    className="input-field" 
                    value={formData.subCategory}
                    onChange={(e) => {
                      const subCategory = e.target.value
                      setFormData(prev => ({ ...prev, subCategory }))
                      handleSubCategoryChange(formData.category, subCategory)
                    }}
                    disabled={!formData.category}
                  >
                    <option value="">Select Sub Category</option>
                    {Object.entries(subCategories).map(([cat, subs]) => (
                      <optgroup key={cat} label={cat}>
                        {subs.map(sub => (
                          <option key={sub} value={sub}>{sub}</option>
                        ))}
                      </optgroup>
                    ))}
                  </select>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Item Name *</label>
                  <input
                    type="text"
                    value={formData.itemName}
                    onChange={(e) => setFormData(prev => ({ ...prev, itemName: e.target.value }))}
                    className="input-field"
                    placeholder="Enter item name (e.g., A4 Paper, Black Ink)"
                    required
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Current Stock</label>
                  <input
                    type="number"
                    min="0"
                    value={formData.currentStock}
                    onChange={(e) => {
                      const currentStock = parseInt(e.target.value) || 0
                      setFormData(prev => ({ ...prev, currentStock }))
                    }}
                    className="input-field"
                    placeholder="Auto-populated when category/subcategory selected"
                    title="Current stock will auto-load if this category/subcategory combination already exists"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Restock</label>
                  <input
                    type="number"
                    min="0"
                    value={formData.restock}
                    onChange={(e) => {
                      const restock = parseInt(e.target.value) || 0
                      setFormData(prev => ({ ...prev, restock }))
                    }}
                    className="input-field"
                    placeholder="Enter restock quantity"
                    title="Additional stock to add to current stock"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Total Stock</label>
                  <div className="w-full px-3 py-2 border border-gray-300 rounded-lg bg-gray-50 text-gray-700">
                    <span className="text-sm font-medium">
                      {(formData.currentStock || 0) + (formData.restock || 0)} {formData.unit || 'units'}
                    </span>
                  </div>
                  <p className="text-xs text-gray-500 mt-1">Current stock + restock (auto-calculated)</p>
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Minimum Stock</label>
                  <input
                    type="number"
                    min="0"
                    value={formData.minStock}
                    onChange={(e) => setFormData(prev => ({ ...prev, minStock: parseInt(e.target.value) || 0 }))}
                    className="input-field"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Unit</label>
                  <input
                    type="text"
                    value={formData.unit}
                    onChange={(e) => setFormData(prev => ({ ...prev, unit: e.target.value }))}
                    className="input-field"
                    placeholder="e.g., Sheets, Cartridges, Bottles"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Unit Price (₹)</label>
                  <input
                    type="number"
                    min="0"
                    step="0.01"
                    value={formData.unitPrice}
                    onChange={(e) => setFormData(prev => ({ ...prev, unitPrice: parseFloat(e.target.value) || 0 }))}
                    className="input-field"
                    placeholder="0.00"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Supplier</label>
                  <input
                    type="text"
                    value={formData.supplier}
                    onChange={(e) => setFormData(prev => ({ ...prev, supplier: e.target.value }))}
                    className="input-field"
                    placeholder="e.g., Office Depot"
                  />
                </div>

                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Last Restocked</label>
                  <input
                    type="date"
                    value={formData.lastRestocked}
                    onChange={(e) => setFormData(prev => ({ ...prev, lastRestocked: e.target.value }))}
                    className="input-field"
                  />
                </div>

                <div className="md:col-span-2">
                  <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                  <textarea
                    value={formData.notes}
                    onChange={(e) => setFormData(prev => ({ ...prev, notes: e.target.value }))}
                    className="input-field"
                    rows={3}
                    placeholder="Additional notes about this stock item..."
                  />
                </div>
              </div>
            </div>

            {/* Modal Footer */}
            <div className="bg-gray-50 px-6 py-4 flex justify-end space-x-3">
              <button
                onClick={() => {
                  setShowAddForm(false)
                  setEditingItem(null)
                  setFormData({
                    itemName: '', // Added missing required field
                    category: '',
                    subCategory: '',
                    currentStock: 0,
                    minStock: 0,
                    restock: 0,
                    unit: '',
                    unitPrice: 0,
                    supplier: '',
                    lastRestocked: '',
                    notes: ''
                  })
                }}
                className="btn-secondary"
              >
                Cancel
              </button>
              <button
                onClick={() => handleSave(formData)}
                className="btn-primary"
              >
                {editingItem ? 'Update Stock Item' : 'Add Stock Item'}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  )
}

export default StockManagement
