import React, { useState } from 'react'
import { Plus, Trash2, Package, CheckCircle, AlertCircle } from 'lucide-react'

const SeparateTableTest = () => {
  const [billItems, setBillItems] = useState([])

  const addBillItem = () => {
    const newItem = {
      id: Date.now(),
      serviceId: '',
      serviceName: '',
      subServiceId: '',
      subServiceName: '',
      quantity: 1,
      unitPrice: 0,
      total: 0,
      category: '',
      subCategory: '',
      totalStock: 0,
      sheetCount: 0,
      wastCount: 0,
      totalCount: 0,
      unit: ''
    }
    setBillItems([...billItems, newItem])
  }

  const updateBillItem = (id, field, value) => {
    const updatedItems = billItems.map(item => {
      if (item.id === id) {
        const updatedItem = { ...item, [field]: value }
        
        // Auto-calculate total count when sheetCount or wastCount changes
        if (field === 'sheetCount' || field === 'wastCount') {
          updatedItem.totalCount = (updatedItem.sheetCount || 0) + (updatedItem.wastCount || 0)
        }
        
        // Auto-calculate total when quantity or price changes
        if (field === 'quantity' || field === 'unitPrice') {
          const quantity = updatedItem.quantity || 0
          const unitPrice = updatedItem.unitPrice || 0
          updatedItem.total = quantity * unitPrice
        }
        
        return updatedItem
      }
      return item
    })
    setBillItems(updatedItems)
  }

  const removeBillItem = (id) => {
    setBillItems(billItems.filter(item => item.id !== id))
  }

  const mockServices = [
    { _id: '1', serviceName: 'Pan Services', price: 300 },
    { _id: '2', serviceName: 'Aadhaar Services', price: 500 },
    { _id: '3', serviceName: 'Printing Services', price: 50 }
  ]

  const mockSubServices = [
    { _id: '1', subServiceName: 'New Pan Card', serviceId: '1', price: 300 },
    { _id: '2', subServiceName: 'Pan Correction', serviceId: '1', price: 200 },
    { _id: '3', subServiceName: 'Aadhaar Update', serviceId: '2', price: 500 },
    { _id: '4', subServiceName: 'Aadhaar Print', serviceId: '2', price: 100 }
  ]

  const mockCategories = ['printing', 'lamination', 'binding']
  const mockSubCategories = {
    'printing': ['offset', 'digital', 'laminated'],
    'lamination': ['matte', 'glossy', 'uv'],
    'binding': ['spiral', 'wiro', 'perfect']
  }

  const getSubServicesForService = (serviceId) => {
    return mockSubServices.filter(ss => ss.serviceId === serviceId)
  }

  const getSubCategoriesForCategory = (category) => {
    return mockSubCategories[category] || []
  }

  const calculateTotals = () => {
    const subtotal = billItems.reduce((sum, item) => sum + item.total, 0)
    const serviceCharges = 50
    const discount = 0
    const grandTotal = subtotal + serviceCharges - discount
    return { subtotal, serviceCharges, discount, grandTotal }
  }

  const totals = calculateTotals()

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <div className="bg-white rounded-lg shadow-lg p-6">
        <div className="flex items-center gap-2 mb-6">
          <Package className="h-6 w-6 text-blue-600" />
          <h1 className="text-2xl font-bold text-gray-800">Separate Tables Test</h1>
        </div>

        <div className="mb-4">
          <button
            onClick={addBillItem}
            className="flex items-center gap-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700"
          >
            <Plus size={16} />
            Add Service
          </button>
        </div>

        {/* Main Billing Table */}
        <div className="mb-6">
          <div className="flex justify-between items-center mb-3">
            <h3 className="text-lg font-semibold text-gray-800">Bill Particulars</h3>
            <div className="text-sm text-gray-500">
              Main billing information
            </div>
          </div>

          <div className="overflow-x-auto rounded-lg shadow-lg border border-gray-200">
            <table className="w-full border-separate border-spacing-0">
              <thead>
                <tr className="bg-gradient-to-r from-blue-600 to-indigo-600 text-white">
                  <th className="px-4 py-3 text-left text-sm font-semibold border-b border-blue-700">S.No</th>
                  <th className="px-4 py-3 text-left text-sm font-semibold border-b border-blue-700">Service</th>
                  <th className="px-4 py-3 text-left text-sm font-semibold border-b border-blue-700">Sub Service</th>
                  <th className="px-4 py-3 text-center text-sm font-semibold border-b border-blue-700">Qty</th>
                  <th className="px-4 py-3 text-right text-sm font-semibold border-b border-blue-700">Price</th>
                  <th className="px-4 py-3 text-right text-sm font-semibold border-b border-blue-700">Total</th>
                  <th className="px-4 py-3 text-center text-sm font-semibold border-b border-blue-700">Action</th>
                </tr>
              </thead>
              <tbody className="bg-white divide-y divide-gray-200">
                {billItems.map((item, index) => (
                  <tr key={item.id} className="hover:bg-gradient-to-r hover:from-blue-50 hover:to-indigo-50 transition-colors duration-200">
                    <td className="px-4 py-3 text-center text-sm font-medium text-gray-900">{index + 1}</td>
                    <td className="px-4 py-3">
                      <select
                        value={item.serviceId}
                        onChange={(e) => {
                          const service = mockServices.find(s => s._id === e.target.value)
                          updateBillItem(item.id, 'serviceId', e.target.value)
                          updateBillItem(item.id, 'serviceName', service?.serviceName || '')
                          updateBillItem(item.id, 'unitPrice', service?.price || 0)
                        }}
                        className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-200 bg-white"
                      >
                        <option value="">Select Service</option>
                        {mockServices.map(service => (
                          <option key={service._id} value={service._id}>
                            {service.serviceName}
                          </option>
                        ))}
                      </select>
                    </td>
                    <td className="px-4 py-3">
                      <select
                        value={item.subServiceId}
                        onChange={(e) => {
                          const subService = mockSubServices.find(ss => ss._id === e.target.value)
                          updateBillItem(item.id, 'subServiceId', e.target.value)
                          updateBillItem(item.id, 'subServiceName', subService?.subServiceName || '')
                          updateBillItem(item.id, 'unitPrice', subService?.price || 0)
                        }}
                        disabled={!item.serviceId}
                        className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-sm focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-200 bg-white disabled:bg-gray-100 disabled:cursor-not-allowed"
                      >
                        <option value="">Select Sub Service</option>
                        {getSubServicesForService(item.serviceId).map(subService => (
                          <option key={subService._id} value={subService._id}>
                            {subService.subServiceName} - ₹{subService.price}
                          </option>
                        ))}
                      </select>
                    </td>
                    <td className="px-4 py-3">
                      <input
                        type="number"
                        min="1"
                        value={item.quantity}
                        onChange={(e) => updateBillItem(item.id, 'quantity', parseInt(e.target.value) || 1)}
                        className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-center text-sm focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-200"
                      />
                    </td>
                    <td className="px-4 py-3">
                      <input
                        type="number"
                        min="0"
                        step="0.01"
                        value={item.unitPrice}
                        onChange={(e) => updateBillItem(item.id, 'unitPrice', parseFloat(e.target.value) || 0)}
                        className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-right text-sm focus:border-blue-500 focus:ring-2 focus:ring-blue-200 transition-all duration-200"
                      />
                    </td>
                    <td className="px-4 py-3 text-right">
                      <div className="text-lg font-bold text-green-600">₹{item.total.toFixed(2)}</div>
                    </td>
                    <td className="px-4 py-3 text-center">
                      <button
                        onClick={() => removeBillItem(item.id)}
                        className="p-2 bg-red-100 text-red-600 rounded-lg hover:bg-red-200 hover:text-red-800 transition-all duration-200 transform hover:scale-110"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
                {billItems.length === 0 && (
                  <tr>
                    <td colSpan="7" className="px-4 py-12 text-center text-gray-500 bg-gray-50">
                      <div className="flex flex-col items-center space-y-2">
                        <Package className="h-12 w-12 text-gray-400" />
                        <span className="text-lg font-medium">No services added</span>
                        <span className="text-sm">Click "Add Service" to add services to bill.</span>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>

        {/* Separate Stock Information Table */}
        {billItems.length > 0 && (
          <div className="mb-6">
            <div className="flex justify-between items-center mb-3">
              <h3 className="text-lg font-semibold text-gray-800">Stock Information</h3>
              <div className="text-sm text-gray-500">
                Category, Sub Category, and Stock details for each service
              </div>
            </div>

            <div className="overflow-x-auto rounded-lg shadow-lg border border-gray-200">
              <table className="w-full border-separate border-spacing-0">
                <thead>
                  <tr className="bg-gradient-to-r from-purple-600 to-pink-600 text-white">
                    <th className="px-4 py-3 text-left text-sm font-semibold border-b border-purple-700">S.No</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold border-b border-purple-700">Service</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold border-b border-purple-700">Category</th>
                    <th className="px-4 py-3 text-left text-sm font-semibold border-b border-purple-700">Sub Category</th>
                    <th className="px-4 py-3 text-center text-sm font-semibold border-b border-purple-700">Total Stock</th>
                    <th className="px-4 py-3 text-center text-sm font-semibold border-b border-purple-700">Sheet Count</th>
                    <th className="px-4 py-3 text-center text-sm font-semibold border-b border-purple-700">Wast Count</th>
                    <th className="px-4 py-3 text-center text-sm font-semibold border-b border-purple-700">Total Count</th>
                    <th className="px-4 py-3 text-center text-sm font-semibold border-b border-purple-700">Status</th>
                  </tr>
                </thead>
                <tbody className="bg-white divide-y divide-gray-200">
                  {billItems.map((item, index) => (
                    <tr key={`stock-${item.id}`} className="hover:bg-gradient-to-r hover:from-purple-50 hover:to-pink-50 transition-colors duration-200">
                      <td className="px-4 py-3 text-center text-sm font-bold text-gray-900 bg-gray-50">{index + 1}</td>
                      <td className="px-4 py-3">
                        <div className="bg-gradient-to-r from-blue-50 to-indigo-50 rounded-lg p-2">
                          <div className="font-semibold text-gray-900 text-sm">{item.serviceName}</div>
                          <div className="text-gray-600 text-xs">{item.subServiceName}</div>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        <select
                          value={item.category}
                          onChange={(e) => updateBillItem(item.id, 'category', e.target.value)}
                          className="w-full border-2 border-purple-300 rounded-lg px-3 py-2 text-sm focus:border-purple-500 focus:ring-2 focus:ring-purple-200 transition-all duration-200 bg-white"
                        >
                          <option value="">Select Category</option>
                          {mockCategories.map(category => (
                            <option key={category} value={category}>
                              {category}
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-4 py-3">
                        <select
                          value={item.subCategory}
                          onChange={(e) => updateBillItem(item.id, 'subCategory', e.target.value)}
                          disabled={!item.category}
                          className="w-full border-2 border-purple-300 rounded-lg px-3 py-2 text-sm focus:border-purple-500 focus:ring-2 focus:ring-purple-200 transition-all duration-200 bg-white disabled:bg-gray-100 disabled:cursor-not-allowed"
                        >
                          <option value="">Select Sub Category</option>
                          {getSubCategoriesForCategory(item.category).map(subCategory => (
                            <option key={subCategory} value={subCategory}>
                              {subCategory}
                            </option>
                          ))}
                        </select>
                      </td>
                      <td className="px-4 py-3">
                        <input
                          type="number"
                          min="0"
                          value={item.totalStock}
                          readOnly
                          className="w-full border-2 border-gray-300 rounded-lg px-3 py-2 text-center text-sm bg-gray-100 font-semibold"
                          placeholder="Auto-populated"
                        />
                      </td>
                      <td className="px-4 py-3">
                        <div className="relative">
                          <input
                            type="number"
                            min="0"
                            value={item.sheetCount}
                            onChange={(e) => updateBillItem(item.id, 'sheetCount', parseInt(e.target.value) || 0)}
                            className="w-full border-2 border-green-300 rounded-lg px-3 py-2 text-center text-sm focus:border-green-500 focus:ring-2 focus:ring-green-200 transition-all duration-200 bg-white font-semibold"
                            placeholder="0"
                          />
                          <div className="absolute -top-2 -right-2 w-4 h-4 bg-green-500 rounded-full flex items-center justify-center">
                            <span className="text-white text-xs font-bold">S</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3">
                        <div className="relative">
                          <input
                            type="number"
                            min="0"
                            value={item.wastCount}
                            onChange={(e) => updateBillItem(item.id, 'wastCount', parseInt(e.target.value) || 0)}
                            className="w-full border-2 border-red-300 rounded-lg px-3 py-2 text-center text-sm focus:border-red-500 focus:ring-2 focus:ring-red-200 transition-all duration-200 bg-white font-semibold"
                            placeholder="0"
                          />
                          <div className="absolute -top-2 -right-2 w-4 h-4 bg-red-500 rounded-full flex items-center justify-center">
                            <span className="text-white text-xs font-bold">W</span>
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-center">
                        <div className="bg-gradient-to-r from-purple-100 to-pink-100 rounded-lg p-2">
                          <div className="text-2xl font-bold text-purple-700">{item.totalCount}</div>
                          <div className="text-xs text-gray-600">
                            ({item.sheetCount || 0} + {item.wastCount || 0})
                          </div>
                        </div>
                      </td>
                      <td className="px-4 py-3 text-center">
                        {item.category && item.subCategory ? (
                          <div className="flex items-center justify-center">
                            <span className="px-3 py-1 text-xs rounded-full bg-gradient-to-r from-green-400 to-green-600 text-white font-semibold shadow-lg">
                              <CheckCircle className="inline h-3 w-3 mr-1" />
                              Available
                            </span>
                          </div>
                        ) : (
                          <div className="flex items-center justify-center">
                            <span className="px-3 py-1 text-xs rounded-full bg-gray-200 text-gray-600 font-medium">
                              <AlertCircle className="inline h-3 w-3 mr-1" />
                              Select Category
                            </span>
                          </div>
                        )}
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Test Results */}
        <div className="bg-gray-50 rounded-lg p-4">
          <h3 className="text-lg font-semibold mb-4">Test Results</h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="space-y-2">
              <div className="flex justify-between">
                <span>Subtotal:</span>
                <span className="font-medium">₹{totals.subtotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>Service Charges:</span>
                <span className="font-medium">₹{totals.serviceCharges.toFixed(2)}</span>
              </div>
              <div className="flex justify-between">
                <span>Discount:</span>
                <span className="font-medium">-₹{totals.discount.toFixed(2)}</span>
              </div>
              <div className="border-t pt-2 flex justify-between text-lg font-bold">
                <span>Grand Total:</span>
                <span className="text-blue-600">₹{totals.grandTotal.toFixed(2)}</span>
              </div>
            </div>
            <div className="p-4 bg-blue-50 border border-blue-200 rounded-lg">
              <div className="flex items-center gap-2 mb-2">
                <CheckCircle className="h-5 w-5 text-blue-600" />
                <h4 className="font-semibold text-blue-800">Separate Tables Features</h4>
              </div>
              <ul className="text-sm text-blue-700 space-y-1">
                <li>✅ Main billing table (simplified)</li>
                <li>✅ Separate stock information table</li>
                <li>✅ Stock table appears when items added</li>
                <li>✅ Data flows between both tables</li>
                <li>✅ Clean visual separation</li>
                <li>✅ Proper stock management fields</li>
              </ul>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

export default SeparateTableTest
