import React, { useState, useEffect } from 'react'
import { useNavigate } from 'react-router-dom'
import { ArrowLeft, Plus, Minus, Wallet, Calendar, FileText, DollarSign, Building, CreditCard, Banknote, ArrowUpDown, Save, X } from 'lucide-react'
import { toast } from 'react-hot-toast'

const AddBalance = () => {
  const navigate = useNavigate()
  
  const [formData, setFormData] = useState({
    type: 'addition', // 'addition' or 'deduction'
    amount: '',
    description: '',
    category: 'general',
    paymentMethod: 'bank_transfer',
    date: new Date().toISOString().split('T')[0],
    reference: '',
    notes: '',
    accountName: '',
    accountNumber: ''
  })
  
  const [loading, setLoading] = useState(false)
  const [errors, setErrors] = useState({})
  const [currentBalance, setCurrentBalance] = useState(0)

  useEffect(() => {
    calculateCurrentBalance()
  }, [])

  const calculateCurrentBalance = () => {
    try {
      // Get balance adjustments from localStorage
      const balanceAdjustments = JSON.parse(localStorage.getItem('bankBalances') || '[]')
      
      // Calculate running balance
      let runningBalance = 0
      balanceAdjustments.forEach(adjustment => {
        if (adjustment.type === 'addition') {
          runningBalance += adjustment.amount || 0
        } else {
          runningBalance -= adjustment.amount || 0
        }
      })
      
      setCurrentBalance(runningBalance)
    } catch (error) {
      console.error('Error calculating current balance:', error)
      setCurrentBalance(0)
    }
  }

  const categories = [
    { value: 'general', label: 'General' },
    { value: 'deposit', label: 'Bank Deposit' },
    { value: 'withdrawal', label: 'Bank Withdrawal' },
    { value: 'transfer', label: 'Fund Transfer' },
    { value: 'adjustment', label: 'Balance Adjustment' },
    { value: 'interest', label: 'Interest' },
    { value: 'fees', label: 'Bank Fees' },
    { value: 'other', label: 'Other' }
  ]

  const paymentMethods = [
    { value: 'bank_transfer', label: 'Bank Transfer' },
    { value: 'cash', label: 'Cash' },
    { value: 'upi', label: 'UPI' },
    { value: 'credit_card', label: 'Credit Card' },
    { value: 'cheque', label: 'Cheque' },
    { value: 'other', label: 'Other' }
  ]

  const validateForm = () => {
    const newErrors = {}
    
    if (!formData.amount || parseFloat(formData.amount) <= 0) {
      newErrors.amount = 'Amount must be greater than 0'
    }
    
    if (!formData.description.trim()) {
      newErrors.description = 'Description is required'
    }
    
    if (!formData.date) {
      newErrors.date = 'Date is required'
    }
    
    setErrors(newErrors)
    return Object.keys(newErrors).length === 0
  }

  const handleInputChange = (e) => {
    const { name, value } = e.target
    setFormData(prev => ({
      ...prev,
      [name]: value
    }))
    
    // Clear error when user starts typing
    if (errors[name]) {
      setErrors(prev => ({
        ...prev,
        [name]: ''
      }))
    }
  }

  const handleSubmit = async (e) => {
    e.preventDefault()
    
    if (!validateForm()) {
      toast.error('Please fix the errors in the form')
      return
    }
    
    setLoading(true)
    
    try {
      // Create balance adjustment transaction
      const balanceData = {
        ...formData,
        amount: parseFloat(formData.amount),
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        status: 'completed'
      }
      
      // For now, store in localStorage (you can integrate with API later)
      const existingBalances = JSON.parse(localStorage.getItem('bankBalances') || '[]')
      existingBalances.push(balanceData)
      localStorage.setItem('bankBalances', JSON.stringify(existingBalances))
      
      toast.success(`Balance ${formData.type === 'addition' ? 'added' : 'deducted'} successfully!`)
      
      // Navigate back to banking ledger
      navigate('/financial?tab=banking-ledger')
      
    } catch (error) {
      console.error('Error adding balance:', error)
      toast.error('Failed to add balance. Please try again.')
    } finally {
      setLoading(false)
    }
  }

  const resetForm = () => {
    setFormData({
      type: 'addition',
      amount: '',
      description: '',
      category: 'general',
      paymentMethod: 'bank_transfer',
      date: new Date().toISOString().split('T')[0],
      reference: '',
      notes: '',
      accountName: '',
      accountNumber: ''
    })
    setErrors({})
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 to-indigo-100 p-4">
      <div className="max-w-4xl mx-auto">
        {/* Header */}
        <div className="bg-white rounded-2xl shadow-xl p-6 mb-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center">
              <button
                onClick={() => navigate('/financial?tab=banking-ledger')}
                className="mr-4 p-2 rounded-lg hover:bg-gray-100 transition-colors"
              >
                <ArrowLeft className="h-6 w-6 text-gray-600" />
              </button>
              <div>
                <h1 className="text-2xl font-bold text-gray-900">Add Balance Adjustment</h1>
                <p className="text-gray-600 mt-1">Add or deduct balance from your bank account</p>
              </div>
            </div>
            <div className="bg-gradient-to-r from-blue-500 to-indigo-500 rounded-2xl p-3">
              <Wallet className="h-8 w-8 text-white" />
            </div>
          </div>
        </div>

        {/* Current Balance Display */}
        <div className="bg-white rounded-2xl shadow-xl p-6 mb-6">
          <div className="flex items-center justify-between">
            <div>
              <h3 className="text-lg font-semibold text-gray-800 mb-2">Current Bank Balance</h3>
              <p className="text-sm text-gray-600">Your current account balance before this adjustment</p>
            </div>
            <div className="text-right">
              <p className="text-3xl font-bold text-gray-900">Rs. {currentBalance.toFixed(2)}</p>
              <p className="text-sm text-gray-500 mt-1">
                {currentBalance >= 0 ? 'Positive Balance' : 'Negative Balance'}
              </p>
            </div>
          </div>
        </div>

        {/* Form */}
        <div className="bg-white rounded-2xl shadow-xl p-8">
          <form onSubmit={handleSubmit} className="space-y-6">
            {/* Transaction Type */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Transaction Type
                </label>
                <div className="grid grid-cols-2 gap-3">
                  <button
                    type="button"
                    onClick={() => setFormData(prev => ({ ...prev, type: 'addition' }))}
                    className={`p-4 rounded-xl border-2 transition-all ${
                      formData.type === 'addition'
                        ? 'border-green-500 bg-green-50 text-green-700'
                        : 'border-gray-200 bg-white text-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <Plus className="h-6 w-6 mx-auto mb-2" />
                    <span className="font-medium">Add Balance</span>
                  </button>
                  <button
                    type="button"
                    onClick={() => setFormData(prev => ({ ...prev, type: 'deduction' }))}
                    className={`p-4 rounded-xl border-2 transition-all ${
                      formData.type === 'deduction'
                        ? 'border-red-500 bg-red-50 text-red-700'
                        : 'border-gray-200 bg-white text-gray-700 hover:border-gray-300'
                    }`}
                  >
                    <Minus className="h-6 w-6 mx-auto mb-2" />
                    <span className="font-medium">Deduct Balance</span>
                  </button>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Amount (Rs.)*
                </label>
                <div className="relative">
                  <DollarSign className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
                  <input
                    type="number"
                    name="amount"
                    value={formData.amount}
                    onChange={handleInputChange}
                    step="0.01"
                    min="0"
                    placeholder="0.00"
                    className={`w-full pl-10 pr-3 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent ${
                      errors.amount ? 'border-red-500' : 'border-gray-300'
                    }`}
                  />
                </div>
                {errors.amount && (
                  <p className="mt-1 text-sm text-red-600">{errors.amount}</p>
                )}
              </div>
            </div>

            {/* Description and Category */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Description*
                </label>
                <input
                  type="text"
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  placeholder="Enter description"
                  className={`w-full px-3 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent ${
                    errors.description ? 'border-red-500' : 'border-gray-300'
                  }`}
                />
                {errors.description && (
                  <p className="mt-1 text-sm text-red-600">{errors.description}</p>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Category
                </label>
                <select
                  name="category"
                  value={formData.category}
                  onChange={handleInputChange}
                  className="w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                >
                  {categories.map(cat => (
                    <option key={cat.value} value={cat.value}>{cat.label}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Date and Payment Method */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Date*
                </label>
                <div className="relative">
                  <Calendar className="absolute left-3 top-1/2 transform -translate-y-1/2 h-5 w-5 text-gray-400" />
                  <input
                    type="date"
                    name="date"
                    value={formData.date}
                    onChange={handleInputChange}
                    className={`w-full pl-10 pr-3 py-3 border rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent ${
                      errors.date ? 'border-red-500' : 'border-gray-300'
                    }`}
                  />
                </div>
                {errors.date && (
                  <p className="mt-1 text-sm text-red-600">{errors.date}</p>
                )}
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Payment Method
                </label>
                <select
                  name="paymentMethod"
                  value={formData.paymentMethod}
                  onChange={handleInputChange}
                  className="w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                >
                  {paymentMethods.map(method => (
                    <option key={method.value} value={method.value}>{method.label}</option>
                  ))}
                </select>
              </div>
            </div>

            {/* Account Details */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Account Name
                </label>
                <input
                  type="text"
                  name="accountName"
                  value={formData.accountName}
                  onChange={handleInputChange}
                  placeholder="Enter account name"
                  className="w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Account Number
                </label>
                <input
                  type="text"
                  name="accountNumber"
                  value={formData.accountNumber}
                  onChange={handleInputChange}
                  placeholder="Enter account number"
                  className="w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>

            {/* Reference and Notes */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Reference Number
                </label>
                <input
                  type="text"
                  name="reference"
                  value={formData.reference}
                  onChange={handleInputChange}
                  placeholder="Enter reference number (optional)"
                  className="w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Notes
                </label>
                <input
                  type="text"
                  name="notes"
                  value={formData.notes}
                  onChange={handleInputChange}
                  placeholder="Additional notes (optional)"
                  className="w-full px-3 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent"
                />
              </div>
            </div>

            {/* Summary */}
            <div className="bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl p-6 border border-blue-200">
              <h3 className="text-lg font-semibold text-gray-800 mb-4">Transaction Summary</h3>
              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
                <div>
                  <p className="text-sm text-gray-600">Type</p>
                  <p className="font-semibold">
                    {formData.type === 'addition' ? (
                      <span className="text-green-600">+ Balance Addition</span>
                    ) : (
                      <span className="text-red-600">- Balance Deduction</span>
                    )}
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-600">Amount</p>
                  <p className="font-semibold text-gray-900">
                    {formData.type === 'addition' ? '+' : '-'}Rs. {formData.amount || '0.00'}
                  </p>
                </div>
                <div>
                  <p className="text-sm text-gray-600">Current Balance</p>
                  <p className="font-semibold text-gray-900">Rs. {currentBalance.toFixed(2)}</p>
                </div>
                <div>
                  <p className="text-sm text-gray-600">New Balance</p>
                  <p className="font-semibold text-gray-900">
                    Rs. {(currentBalance + (formData.type === 'addition' ? parseFloat(formData.amount || 0) : -parseFloat(formData.amount || 0))).toFixed(2)}
                  </p>
                </div>
              </div>
            </div>

            {/* Action Buttons */}
            <div className="flex gap-4 pt-6">
              <button
                type="button"
                onClick={resetForm}
                className="flex-1 bg-gray-100 text-gray-700 px-6 py-3 rounded-xl hover:bg-gray-200 transition-colors font-medium flex items-center justify-center"
              >
                <X className="h-5 w-5 mr-2" />
                Reset
              </button>
              <button
                type="submit"
                disabled={loading}
                className="flex-1 bg-gradient-to-r from-blue-500 to-indigo-500 text-white px-6 py-3 rounded-xl hover:from-blue-600 hover:to-indigo-600 transition-all font-medium flex items-center justify-center disabled:opacity-50"
              >
                {loading ? (
                  <>
                    <div className="animate-spin rounded-full h-5 w-5 border-b-2 border-white mr-2"></div>
                    Processing...
                  </>
                ) : (
                  <>
                    <Save className="h-5 w-5 mr-2" />
                    {formData.type === 'addition' ? 'Add Balance' : 'Deduct Balance'}
                  </>
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </div>
  )
}

export default AddBalance
