import { useState, useEffect } from 'react'
import { Plus, Edit2, Trash2, Save, X, Search, Filter } from 'lucide-react'
import { toast } from 'react-hot-toast'

// Helper function to get API base URL
const getApiUrl = (endpoint) => {
  const baseUrl = window.location.hostname === 'localhost' || window.location.hostname === '127.0.0.1'
    ? 'http://localhost:5001'
    : 'https://two026backend.onrender.com'
  return `${baseUrl}${endpoint}`
}

const Services = () => {
  const [services, setServices] = useState([])
  const [showAddForm, setShowAddForm] = useState(false)
  const [editingService, setEditingService] = useState(null)
  const [searchTerm, setSearchTerm] = useState('')
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  
  // Form state for proper handling
  const [formData, setFormData] = useState({
    serviceName: '',
    description: '',
    url: '',
    isActive: true
  })

  // Update form data when editing service
  useEffect(() => {
    if (editingService) {
      setFormData({
        serviceName: editingService.serviceName || '',
        description: editingService.description || '',
        url: editingService.url || '',
        isActive: editingService.isActive !== undefined ? editingService.isActive : true
      })
    }
  }, [editingService])

  // Reset form when modal closes (but only if not editing)
  useEffect(() => {
    if (!showAddForm && !editingService) {
      console.log('Resetting form - modal closed without editing')
      setFormData({
        serviceName: '',
        description: '',
        url: '',
        isActive: true
      })
    }
  }, [showAddForm, editingService])

  // Fetch services from backend
  const fetchServices = async () => {
    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch(getApiUrl('/api/services'), {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })
      
      if (response.ok) {
        const data = await response.json()
        setServices(Array.isArray(data) ? data : [])
      } else {
        setError('Failed to fetch services')
      }
    } catch (err) {
      console.error('Error fetching services:', err)
      setError('Failed to fetch services')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    fetchServices()
  }, [])

  // Save service
  const saveService = async (serviceData) => {
    try {
      console.log('=== SAVE SERVICE DEBUG ===')
      console.log('Service data received:', serviceData)
      console.log('Is editing:', !!editingService)
      console.log('Editing service ID:', editingService?._id)
      
      const token = localStorage.getItem('authToken')
      const url = editingService ? getApiUrl(`/api/services/${editingService._id}`) : getApiUrl('/api/services')
      const method = editingService ? 'PUT' : 'POST'
      
      console.log('Request URL:', url)
      console.log('Request method:', method)
      console.log('Request body:', JSON.stringify(serviceData, null, 2))

      const response = await fetch(url, {
        method,
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`
        },
        body: JSON.stringify(serviceData)
      })

      console.log('Response status:', response.status)
      console.log('Response ok:', response.ok)

      if (response.ok) {
        const responseData = await response.json()
        console.log('Response data:', responseData)
        toast.success(editingService ? 'Service updated successfully!' : 'Service added successfully!')
        setShowAddForm(false)
        setEditingService(null)
        fetchServices() // Refresh services list
      } else {
        const errorData = await response.json()
        console.error('Error response:', errorData)
        toast.error('Failed to save service')
      }
    } catch (err) {
      console.error('Error saving service:', err)
      toast.error('Failed to save service')
    }
  }

  // Delete service
  const deleteService = async (id) => {
    if (!confirm('Are you sure you want to delete this service?')) {
      return
    }

    try {
      const token = localStorage.getItem('authToken')
      const response = await fetch(getApiUrl(`/api/services/${id}`), {
        method: 'DELETE',
        headers: {
          'Authorization': `Bearer ${token}`
        }
      })

      if (response.ok) {
        toast.success('Service deleted successfully!')
        // Clear localStorage cache to force refresh in other components
        localStorage.removeItem('services')
        localStorage.removeItem('subServices')
        // Add a small delay to ensure backend is updated
        setTimeout(() => {
          fetchServices() // Refresh services list
        }, 100)
      } else {
        toast.error('Failed to delete service')
      }
    } catch (err) {
      console.error('Error deleting service:', err)
      toast.error('Failed to delete service')
    }
  }

  // Filter services
  const filteredServices = services.filter(service =>
    service.serviceName?.toLowerCase().includes(searchTerm.toLowerCase())
  )

  // Handle form input changes
  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target
    console.log(`Input change - ${name}:`, type === 'checkbox' ? checked : value)
    setFormData(prev => ({
      ...prev,
      [name]: type === 'checkbox' ? checked : value
    }))
  }

  const handleSubmit = (e) => {
    e.preventDefault()
    
    // Debug logging to check form data
    console.log('Form submission data:', formData)
    console.log('Editing service:', editingService)
    
    const serviceData = {
      serviceName: formData.serviceName,
      description: formData.description,
      url: formData.url,
      isActive: formData.isActive
    }
    
    console.log('Service data to save:', serviceData)
    saveService(serviceData)
  }

  const handleEdit = (service) => {
    setEditingService(service)
    setShowAddForm(true)
  }

  const handleAdd = () => {
    setEditingService(null)
    setShowAddForm(true)
  }

  const handleClose = () => {
    setShowAddForm(false)
    setEditingService(null)
    // Reset form data
    setFormData({
      serviceName: '',
      description: '',
      url: '',
      isActive: true
    })
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    )
  }

  return (
    <div className="p-6">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Service Management</h2>
        <button
          onClick={handleAdd}
          className="flex items-center gap-2 bg-blue-600 text-white px-6 py-3 rounded-lg hover:bg-blue-700 transition-colors text-base font-medium"
        >
          <Plus size={20} />
          Add Service
        </button>
      </div>

      {/* Search */}
      <div className="mb-6">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400" size={18} />
          <input
            type="text"
            placeholder="Search services..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
            className="pl-10 pr-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 w-full"
          />
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="mb-4 p-4 bg-red-100 border border-red-400 text-red-700 rounded-lg">
          {error}
        </div>
      )}

      {/* Services List */}
      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full">
            <thead className="bg-gray-50">
              <tr>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Service Name</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Description</th>
                <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Status</th>
                <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Actions</th>
              </tr>
            </thead>
            <tbody className="bg-white divide-y divide-gray-200">
              {filteredServices.length === 0 ? (
                <tr>
                  <td colSpan="4" className="px-6 py-4 text-center text-gray-500">
                    No services found
                  </td>
                </tr>
              ) : (
                filteredServices.map((service) => (
                  <tr key={service._id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap">
                      <div className="text-sm font-medium text-gray-900">{service.serviceName}</div>
                      <div className="text-sm text-gray-500">{service.description}</div>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                      {service.description}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                        service.isActive ? 'bg-green-100 text-green-800' : 'bg-red-100 text-red-800'
                      }`}>
                        {service.isActive ? 'Active' : 'Inactive'}
                      </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                      <button
                        onClick={() => handleEdit(service)}
                        className="text-blue-600 hover:text-blue-900 mr-3 p-2 hover:bg-blue-50 rounded-lg transition-colors"
                        title="Edit Service"
                      >
                        <Edit2 size={18} />
                      </button>
                      <button
                        onClick={() => deleteService(service._id)}
                        className="text-red-600 hover:text-red-900 p-2 hover:bg-red-50 rounded-lg transition-colors"
                        title="Delete Service"
                      >
                        <Trash2 size={18} />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Add/Edit Service Modal */}
      {showAddForm && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 overflow-y-auto h-full w-full z-50">
          <div className="relative top-20 mx-auto p-5 border w-96 shadow-lg rounded-md bg-white">
            <div className="flex justify-between items-center mb-4">
              <h3 className="text-lg font-medium text-gray-900">
                {editingService ? 'Edit Service' : 'Add New Service'}
              </h3>
              <button
                onClick={handleClose}
                className="text-gray-400 hover:text-gray-500"
              >
                <X size={24} />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Service Name</label>
                <input
                  type="text"
                  name="serviceName"
                  value={formData.serviceName}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea
                  name="description"
                  rows="3"
                  value={formData.description}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">URL</label>
                <input
                  type="url"
                  name="url"
                  value={formData.url}
                  onChange={handleInputChange}
                  placeholder="https://example.com"
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Status</label>
                <select
                  name="isActive"
                  value={formData.isActive.toString()}
                  onChange={(e) => handleInputChange({ ...e, target: { ...e.target, value: e.target.value === 'true' } })}
                  className="w-full px-3 py-2 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
                >
                  <option value="true">Active</option>
                  <option value="false">Inactive</option>
                </select>
              </div>

              <div className="flex justify-end space-x-3 pt-4">
                <button
                  type="button"
                  onClick={handleClose}
                  className="px-6 py-3 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50 text-base font-medium transition-colors"
                >
                  Cancel
                </button>
                <button
                  type="submit"
                  className="px-6 py-3 bg-blue-600 text-white rounded-md hover:bg-blue-700 flex items-center gap-2 text-base font-medium transition-colors"
                >
                  <Save size={18} />
                  {editingService ? 'Update' : 'Save'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  )
}

export default Services
